using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
public class Script {
    public static object Main() {
        var controllers = Object.FindObjectsOfType<AnimalController>();
        var sb = new System.Text.StringBuilder();
        foreach (var c in controllers) {
            var sd = c.StateData;
            if (sd == null) continue;
            var animator = c.GetComponentInChildren<Animator>();
            string animInfo = "no-animator";
            if (animator != null) {
                var clipInfo = animator.GetCurrentAnimatorClipInfo(0);
                animInfo = clipInfo.Length > 0 ? clipInfo[0].clip.name : "no-clip";
            }
            sb.AppendLine($"Entity={sd.EntityId} Type={sd.AnimalType} AnimalState={sd.AnimalState} IdleSub={sd.IdleSubState} Speed={sd.MoveSpeed:F2} Anim={animInfo}");
        }
        return sb.Length > 0 ? sb.ToString() : "No animals";
    }
}
